I was able to add JSONField support in my resources by doing this:

```
import json
from import_export import widgets

class JSONWidget(widgets.Widget):
    """ Convert data into JSON for serialization.
    """
    def clean(self, value, row=None, *args, **kwargs):
        return json.loads(value)

    def render(self, value, obj=None):
        if value is None:
            return ""
        return json.dumps(value)


class JSONResourceMixin(object):
    """ Override ModelResource to provide JSON field support.
    """
    @classmethod
    def widget_from_django_field(cls, f, default=widgets.Widget):

        if f.get_internal_type() in ('JSONField', ):
            return JSONWidget
        else:
            return super().widget_from_django_field(f)

```

And then when defining a resource that has a JSONField:

```
class MyResource(JSONResourceMixin, resources.ModelResource):
    ...
```

