    if ($authorization['_'] === 'account.noPassword') {
        logger('a');
        throw new \danog\MadelineProto\Exception('2FA is enabled but no password is set!');
    }
    if ($authorization['_'] === 'account.password') {
        logger('b');
        $authorization = $MadelineProto->complete_2fa_login(readline('Please enter your password (hint ' . $authorization['hint'] . '): '));
    }
    if ($authorization['_'] === 'account.needSignup') {
        logger('c');
        $authorization = $MadelineProto->complete_signup(readline('Please enter your first name: '), readline('Please enter your last name (can be empty): '));
    }
    $MadelineProto->session = 'session.madeline';
    $MadelineProto->serialize('/home/<hidden>/public_html/session.madeline');
}

global $runningLoop;
$runningLoop = true;
pcntl_signal(SIGTERM, function ($signal)
{
    global $runningLoop;
    $runningLoop = FALSE;
});
while ($runningLoop) {
    $a = mysqli_query($conn, "SELECT * FROM channel");
    while ($row = mysqli_fetch_array($a)) {
        try {
            $me = null;
            $id = $row['id'];
            $last = $row['last'];
            $last = $last + 1;
            $last = $last - 1;
            $star = $row['star'];
            $dasteh = $row['dasteh'];
            $lang = $row['lang'];
            $messages_PeerDialogs = $MadelineProto->messages->getPeerDialogs(['peers' => ["$id"],]);
            $top = $messages_PeerDialogs['dialogs'][0]['top_message'];
            if ( $top-$last >= 100) {
                $last = $top - 100;
                mysqli_query($conn, "update channel set last=$last WHERE id='$id'");
            }
            while ($last < $top) {
                if ($top > $last) {
                    if ($top - $last >= 150) {
                        $top = $last + 150;
                    }
                    $ids=null;
                    for ($i = $last; $i < $top; $i++) {
                        $ids[] = $i;
                    }
                    $messages_Messages = $MadelineProto->channels->getMessages(['channel' => "$id", 'id' => $ids,]);
                    for ($i = 0; $i < count($ids); $i++) {
                        if ($messages_Messages['messages'][$i]['_'] == "message") {
                            if (array_key_exists("media", $messages_Messages['messages'][$i])) {
                                $me[] = $messages_Messages['messages'][$i]['id'];
                                $Updates = $MadelineProto->messages->forwardMessages(['from_peer' => "$id", 'id' => $me, 'to_peer' => "@<hidden>bot",]);
                                $me = null;

                            } else {
                                $date = $messages_Messages['messages'][$i]['date'];
                                $d = date("Y-m-d", $date);
                                mysqli_query($conn, "insert into posts VALUE ('$id','" . $messages_Messages['messages'][$i]['message'] . "',Null,'text',$star,$dasteh,'$d',true,$lang)");
                            }
                        }
                        mysqli_query($conn, "update channel set last=last+1 where id='$id'");
                        $last = $last + 1;
                    }
                    sleep(30);
                }
            }
        } catch (Exception $e) {
            $c = $e->getMessage();
            if (strstr($c, "Flood_wait")) {
                $id = preg_replace("/[^0-9]/", '', $c);
                sleep($id);
            }
        }
    }
}
`

